import { useState } from "react";

function InputBox({ onSend, disabled }) {
    const [text, setText] = useState("");

    const handleSend = () => {
        if (!text.trim() || disabled) return;
        onSend(text);
        setText("");
    };

    const handleKeyDown = (e) => {
        if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault();
            handleSend();
        }
    };

    return (
        <div
            style={{
                padding: "20px",
                backgroundColor: "#f8fafc",
                borderTop: "1px solid #e5e7eb",
            }}
        >
            <div
                style={{
                    maxWidth: "900px",
                    margin: "0 auto",
                    display: "flex",
                    alignItems: "center",
                    backgroundColor: "white",
                    borderRadius: "14px",
                    padding: "8px",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                }}
            >
                <textarea
                    value={text}
                    disabled={disabled}
                    onChange={(e) => setText(e.target.value)}
                    onKeyDown={handleKeyDown}
                    placeholder={
                        disabled
                            ? "AI is responding…"
                            : "Send a message"
                    }
                    rows={1}
                    style={{
                        flex: 1,
                        resize: "none",
                        border: "none",
                        outline: "none",
                        padding: "14px",
                        fontSize: "16px",
                        lineHeight: "1.5",
                        backgroundColor: "transparent",
                    }}
                />

                <button
                    onClick={handleSend}
                    disabled={disabled}
                    style={{
                        marginLeft: "8px",
                        padding: "12px 16px",
                        borderRadius: "10px",
                        border: "none",
                        backgroundColor: "#2563eb",
                        color: "white",
                        fontSize: "16px",
                        cursor: disabled ? "not-allowed" : "pointer",
                        opacity: disabled ? 0.6 : 1,
                    }}
                >
                    ➤
                </button>
            </div>

            {/* FOOTER NOTE (LIKE GPT) */}
            <div
                style={{
                    marginTop: "8px",
                    textAlign: "center",
                    fontSize: "12px",
                    color: "#9ca3af",
                }}
            >
                AI can make mistakes. Verify important information.
            </div>
        </div>
    );
}

export default InputBox;
